    academicVibe: string;
    socialVibe: string;
    clubs: { name: string; category: string }[];
    sports: string[];
    nightlife: string;
    weekendSpots: string[];
    campusFacilities: string[];
    studentQuotes: { quote: string; author: string; year: string }[];
