function transformNewUniversity(nu: NewUniversity | ExtraUniversity): University {
  const country = nu.country;
  const city = nu.city;
  const programs = nu.programs.map(p => ({
    name: p.name,
    level: p.level as "UG" | "PG" | "PhD" | "Diploma" | "Certificate",
    duration: p.duration,
    tuition: p.tuition,
    description: p.description,
    requirements: [`Bachelor's degree in related field (65%+)`, `IELTS: 6.5+ / TOEFL: 80+`],
    intakes: nu.deadlines.map(d => d.intake),
  }));

  const scholarships = nu.scholarships.map(s => ({
    name: s.name,
    amount: s.amount,
    eligibility: s.eligibility,
    deadline: s.deadline,
    type: "Merit" as const,
  }));

  // Build campus life from the flat structure
  const campusLife = nu.campusLife || {};
  const newCampusLife = {
    indianAssoc: campusLife.indianAssoc || `${nu.name} Indian Students Association`,
    indianClubs: campusLife.indianClubs || [`ISA ${city}`, `${nu.name} Indian Society`],
    festivals: campusLife.festivals || ["Diwali Night", "Holi Festival"],
    accommodation: campusLife.accommodation || `On-campus and off-campus housing in ${city}`,
    avgRent: campusLife.avgRent || "Contact university for current rates",
    foodOptions: campusLife.foodOptions || `Campus dining halls + ${city} restaurants`,
    indianFood: campusLife.indianFood || `${city} has Indian restaurants nearby`,
    weather: campusLife.weather || "Varies by season — check local climate data",
    transport: campusLife.transport || `Public transport available in ${city}`,
    healthcare: campusLife.healthcare || `Student health insurance required`,
    safety: campusLife.safety || "Safe — standard precautions recommended",
    nearbyAttractions: campusLife.nearbyAttractions || [`${city} city centre`],
    dayInLife: campusLife.dayInLife || [{ time: "9:00 AM", activity: `Morning classes at ${nu.name} campus`, emoji: "🎓" }],
    academicVibe: nu.academicVibe || `Study-focused environment at ${nu.name}`,
    socialVibe: nu.socialVibe || `Welcoming international community at ${nu.name}`,
    clubs: nu.clubs || [{ name: "International Student Society", category: "Cultural" }],
    sports: campusLife.sports || ["Football", "Basketball", "Swimming"],
    nightlife: nu.nightlife || `${city} nightlife — bars, clubs, and entertainment`,
    weekendSpots: nu.weekendSpots || [`${city} attractions`, `Weekend trips from ${city}`],
    campusFacilities: campusLife.campusFacilities || [`${nu.name} Library`, "Student Centre", "Sports Complex"],
    studentQuotes: (nu.studentQuotes || []).map((sq: any) => ({
      quote: typeof sq === 'string' ? sq : sq.quote || "",
      author: typeof sq === 'string' ? "" : sq.author || "",
      year: "2024",
    })),
    genderRatio: nu.genderRatio || "50:50",
    intlStudentPercent: nu.intlStudentPercent || "30%",
  };

  // Build admission requirements
  const ar = nu.admissionReq || {};
  const admissionReq = {
    gpa: ar.gpa || "65%+",
    gre: ar.gre || "Not required",
    gmat: ar.gmat || "Not required",
    ielts: ar.ielts || "6.5 / TOEFL 80",
    toefl: ar.toefl || "80",
    pte: ar.pte || "65",
    duolingo: ar.duolingo || "120",
    workExp: ar.workExp || "Not required",
    lor: ar.lor || "2",
    sop: ar.sop || "Required",
    resume: ar.resume || "Required",
    interview: ar.interview || "Not required",
    applicationFee: ar.applicationFee || "Contact university",
    documents: ["Transcripts", "Degree certificate", "Passport", "SOP", "LORs", "Resume", "Financial proof"],
  };

  // Build career outcomes
  const co = nu.careerOutcomes || {};
  const careerOutcomes = {
    avgSalary: co.avgSalary || "Contact university",
    topEmployers: co.topEmployers || ["Major companies in the industry"],
    placementRate: co.placementRate || "Contact university",
    prPathway: co.prPathway || "Varies by country",
    workVisaDuration: co.workVisaDuration || "Check immigration website",
    internships: co.internships || `Internship opportunities available`,
  };

  // Build cost of living from available data
  const costOfLiving = [
    { category: "Tuition", cost: programs[0]?.tuition || "Contact university" },
    { category: "Accommodation", cost: newCampusLife.avgRent },
    { category: "Food", cost: "Estimated based on location" },
    { category: "Transport", cost: newCampusLife.transport },
    { category: "Health Insurance", cost: newCampusLife.healthcare },
    { category: "Personal", cost: "Varies by lifestyle" },
  ];

  // Build reviews
  const reviews = nu.studentQuotes ? nu.studentQuotes.map((sq: any, idx: number) => ({
    name: typeof sq === 'string' ? `Student ${idx + 1}` : sq.author?.split(",")[0] || `Student ${idx + 1}`,
    course: programs[0]?.name || "Various Programs",
    year: "2024",
    rating: 5,
    review: typeof sq === 'string' ? sq : sq.quote || "",
  })) : [];

  // Build placement data
  const placementData = {
    year: "2024",
    overallPlacementRate: careerOutcomes.placementRate,
    avgSalary: careerOutcomes.avgSalary,
    highestSalary: "Contact university",
    totalCompanies: "Multiple hiring companies",
    topHiringCompanies: careerOutcomes.topEmployers,
    courseWise: programs.map(p => ({
      course: p.name,
      placementRate: "Contact university",
      avgSalary: "Contact university",
      topRoles: p.description ? [p.description.split(".")[0]] : ["Various roles"],
    })),
    dataSources: ["University Career Services"],
  };

  // Build videos
  const videos = [
    { title: `${nu.name} Campus Tour`, embedUrl: `https://www.youtube.com/results?search_query=${encodeURIComponent(nu.name)}+campus+tour`, thumbnail: campusImageMap[country] || "", duration: "5:00", category: "Campus Tour" as const },
    { title: `Student Life at ${nu.name}`, embedUrl: `https://www.youtube.com/results?search_query=${encodeURIComponent(nu.name)}+student+life`, thumbnail: campusImageMap[country] || "", duration: "4:00", category: "Student Life" as const },
  ];

  const deadlineYear = "2025";
  const deadlines = nu.deadlines.map(d => ({
    intake: d.intake,
    deadline: d.deadline,
    decisionDate: d.decisionDate,
  }));

  return {
    id: nu.id,
    name: nu.name,
    slug: nu.slug,
    country,
    countryCode: countryCodeMap[country] || "",
    city,
    state: nu.state,
    type: nu.type as "Public" | "Private",
    founded: nu.founded,
    qsRanking: nu.qsRanking,
    usNewsRanking: nu.usNewsRanking,
    timesRanking: nu.timesRanking,
    website: nu.website,
    logo: undefined,
    heroImage: heroImageMap[country] || "/universities/europe-campus.jpg",
    campusImage: campusImageMap[country] || "",
    acceptanceRate: nu.acceptanceRate,
    totalStudents: nu.totalStudents,
    indianStudents: nu.indianStudents,
    studentFacultyRatio: nu.studentFacultyRatio,
    graduationRate: nu.graduationRate,
    tagline: nu.tagline,
    description: nu.description,
    whyThisUni: nu.whyThisUni,
    programs,
    scholarships,
    admissionReq,
    deadlines,
    campusLife: newCampusLife,
    careerOutcomes,
    notableAlumni: nu.notableAlumni || [],
    costOfLiving,
    reviews,
    placementData,
    videos,
  } as University;
}

