export function getUniversityBySlug(slug: string): University | undefined {
  return universities.find((u) => u.slug === slug);
}

// Transform extra universities
const transformedExtraUniversities: University[] = extraUniversities.map(transformNewUniversity);

export function getAllUniversities(): University[] {
  // Merge existing universities with transformed new and extra universities
  // Filter out any duplicates (by id) in case some already exist
  const existingIds = new Set(universities.map(u => u.id));
  const uniqueNew = transformedNewUniversities.filter(u => !existingIds.has(u.id));
  const allIds = new Set([...existingIds, ...uniqueNew.map(u => u.id)]);
  const uniqueExtra = transformedExtraUniversities.filter(u => !allIds.has(u.id));
  return [...universities, ...uniqueNew, ...uniqueExtra];
}

export function getUniversitiesByCountry(country: string): University[] {
  return universities.filter((u) => u.country.toLowerCase() === country.toLowerCase());
}

export function getUniversitySlugs(): string[] {
  return universities.map((u) => u.slug);
}

export default universities;
